const crypto = require('crypto');

// Extract request data
const body = JSON.stringify($input.all()[0].json.body);
const providedSignature = $input.all()[0].json.headers['x-signature'];
const timestamp = parseInt($input.all()[0].json.headers['x-timestamp']);
const documentId = $input.all()[0].json.body.document_id;

// Check timestamp (replay attack protection - max 5 minutes old)
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - timestamp) > 300) {
  throw new Error('ERR_HMAC_INVALID: Timestamp outside acceptable range (replay attack)');
}

// Get webhook secret from credentials
const webhookSecret = $credentials.laravelWebhookSecret.secret;

// Compute HMAC
const computedSignature = crypto
  .createHmac('sha256', webhookSecret)
  .update(body)
  .digest('hex');

// Timing-safe comparison
if (crypto.timingSafeEqual(Buffer.from(providedSignature), Buffer.from(computedSignature))) {
  // Valid signature - pass through
  return $input.all()[0].json.body;
} else {
  throw new Error(`ERR_HMAC_INVALID: Signature mismatch for document ${documentId}`);
}

const supplierId = $json.supplier_id;
const documentId = $json.document_id;

throw new Error(`ERR_SUPPLIER_NOT_CONFIG: Supplier ID ${supplierId} not configured in N8n workflow (document: ${documentId})`);

// AIR processing deferred to Laravel AirFileParser
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      document_id: item.json.document_id,
      document_type: 'air',
      extraction_status: 'deferred',
      extraction_method: 'laravel-airfileparser-fallback',
      message: 'AIR file processing deferred to Laravel AirFileParser (N8n Phase 2 limitation)',
      file_path: item.json.file_path,
      company_id: item.json.company_id,
      supplier_id: item.json.supplier_id,
      callback_url: item.json.callback_url,
      processing_timestamp: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    let extractedText = '';

    if (item.binary && item.binary.data) {
      extractedText = item.binary.data.toString('utf-8');
    } else if (item.json && item.json.data) {
      extractedText = item.json.data;
    } else if (typeof item.json === 'string') {
      extractedText = item.json;
    }

    if (!extractedText || extractedText.trim().length === 0) {
      throw new Error('ERR_INSUFFICIENT_DATA: Tika extracted no text from PDF');
    }

    results.push({
      json: {
        document_id: $('Read PDF File').item.json.document_id,
        document_type: 'pdf',
        extracted_text: extractedText.trim(),
        extraction_method: 'tika',
        file_path: $('Read PDF File').item.json.file_path,
        company_id: $('Read PDF File').item.json.company_id,
        supplier_id: $('Read PDF File').item.json.supplier_id,
        callback_url: $('Read PDF File').item.json.callback_url,
        text_length: extractedText.trim().length,
        processing_timestamp: new Date().toISOString()
      }
    });
  } catch (error) {
    results.push({
      json: {
        document_id: $('Read PDF File').item.json.document_id,
        document_type: 'pdf',
        extraction_status: 'error',
        error_code: error.message.includes('ERR_') ? error.message.split(':')[0] : 'ERR_EXTRACTION_FAILED',
        error_message: error.message,
        file_path: $('Read PDF File').item.json.file_path,
        company_id: $('Read PDF File').item.json.company_id,
        supplier_id: $('Read PDF File').item.json.supplier_id,
        callback_url: $('Read PDF File').item.json.callback_url
      }
    });
  }
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const response = item.json;

    if (!response || !response.text || response.text.trim().length === 0) {
      throw new Error('ERR_INSUFFICIENT_DATA: Gutenberg extracted no text from image');
    }

