        supplier_id: $('Extract Image with Gutenberg').first().json.supplier_id,
        callback_url: $('Extract Image with Gutenberg').first().json.callback_url,
        text_length: response.text.trim().length,
        processing_timestamp: new Date().toISOString()
      }
    });
  } catch (error) {
    results.push({
      json: {
        document_id: $('Extract Image with Gutenberg').first().json.document_id,
        document_type: 'image',
        extraction_status: 'error',
        error_code: error.message.includes('ERR_') ? error.message.split(':')[0] : 'ERR_EXTRACTION_FAILED',
        error_message: error.message,
        file_path: $('Extract Image with Gutenberg').first().json.file_path,
        company_id: $('Extract Image with Gutenberg').first().json.company_id,
        supplier_id: $('Extract Image with Gutenberg').first().json.supplier_id,
        callback_url: $('Extract Image with Gutenberg').first().json.callback_url
      }
    });
  }
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const input = item.json;

  const extractionResult = {
    tasks: [],
    metadata: {
      extraction_method: input.extraction_method,
      document_type: input.document_type,
      supplier_id: input.supplier_id,
      company_id: input.company_id,
      file_path: input.file_path,
      confidence_score: input.confidence_score || null,
      text_length: input.text_length || null,
      processing_timestamp: input.processing_timestamp || new Date().toISOString()
    }
  };

  if (input.document_type === 'air' && input.extraction_status === 'deferred') {
    extractionResult.deferred = true;
    extractionResult.message = input.message;

    results.push({
      json: {
        document_id: input.document_id,
        extraction_status: 'deferred',
        extraction_result: extractionResult,
        callback_url: input.callback_url
      }
    });
    continue;
  }

  if (input.extraction_status === 'error') {
    results.push({
      json: {
        document_id: input.document_id,
        extraction_status: 'error',
        error: {
          code: input.error_code,
          message: input.error_message,
          context: {
            document_type: input.document_type,
            file_path: input.file_path
          }
        },
        callback_url: input.callback_url
      }
    });
    continue;
  }

  const text = input.extracted_text || '';
  const hasFlightKeywords = /flight|ticket|booking|PNR|passenger|airline|itinerary/i.test(text);

  if (hasFlightKeywords) {
    const task = {
      task_type: 'flight',
      status: 'pending_review',
      reference_number: extractReferenceNumber(text),
      passenger_name: extractPassengerName(text),
      amount: null,
      currency: null,
      notes: text.substring(0, 500),
      extracted_at: new Date().toISOString()
    };
    extractionResult.tasks.push(task);
  } else {
    extractionResult.tasks.push({
      task_type: 'unknown',
      status: 'pending_manual_classification',
      notes: text.substring(0, 500),
      extracted_at: new Date().toISOString()
    });
  }

  if (input.document_type === 'email') {
    extractionResult.metadata.email_subject = input.email_subject || '';
    extractionResult.metadata.email_from = input.email_from || '';
    extractionResult.metadata.email_date = input.email_date || '';
  }

  results.push({
    json: {
      document_id: input.document_id,
      extraction_status: input.extraction_status || 'success',
      extraction_result: extractionResult,
      callback_url: input.callback_url
    }
  });
}

function extractReferenceNumber(text) {
  const pnrMatch = text.match(/PNR[:\s]+([A-Z0-9]{6})/i);
  if (pnrMatch) return pnrMatch[1];

  const bookingMatch = text.match(/booking[\s#:]+([A-Z0-9]{6,10})/i);
  if (bookingMatch) return bookingMatch[1];

  const refMatch = text.match(/reference[\s#:]+([A-Z0-9]{6,10})/i);
  if (refMatch) return refMatch[1];

  return null;
}

function extractPassengerName(text) {
  const nameMatch = text.match(/passenger[:\s]+([A-Z][A-Z\s]{2,40})/i);
  if (nameMatch) return nameMatch[1].trim();

  const mrMatch = text.match(/(?:MR|MRS|MS|MISS)[\s.]+([A-Z][A-Z\s]{2,40})/i);
  if (mrMatch) return mrMatch[1].trim();

  return null;
}

return results;

const crypto = require('crypto');

const callbackPayload = {
  document_id: $json.document_id,
  status: $json.extraction_status || 'error',
  execution_id: $execution.id,
  workflow_id: $workflow.id,
  execution_time_ms: Math.floor($execution.resumeTime ? ($execution.resumeTime - $execution.startTime) : 0),
  extraction_result: $json.extraction_result || null,
  error: $json.error || null
};

const body = JSON.stringify(callbackPayload);
const webhookSecret = $credentials.laravelWebhookSecret.secret;
const hmac = crypto.createHmac('sha256', webhookSecret).update(body).digest('hex');

return {
  json: {
    ...callbackPayload,
    hmac: hmac,
    callback_url: $json.callback_url
  }
};
